import React, { useState, useCallback } from 'react';
import { Upload, AlertCircle, CheckCircle, Clock, Heart, Activity, FileText, ChevronDown, ChevronUp } from 'lucide-react';
import './App.css';

interface EcoResult {
  tem_estenose: boolean;
  gravidade: string;
  area_valvar: number | null;
  gradiente_medio: number | null;
  velocidade_maxima: number | null;
  prioridade: string;
  justificativa: string;
  indicacao_tavi: boolean;
  confianca: number;
}

interface LaudoProcessado {
  arquivo: string;
  timestamp: string;
  analise: EcoResult;
}

function App() {
  const [laudos, setLaudos] = useState<LaudoProcessado[]>([]);
  const [loading, setLoading] = useState(false);
  const [erro, setErro] = useState<string | null>(null);
  const [dragActive, setDragActive] = useState(false);
  const [expandedCard, setExpandedCard] = useState<number | null>(null);

  const processarLaudos = async (files: FileList | null) => {
    if (!files || files.length === 0) return;

    setLoading(true);
    setErro(null);

    const formData = new FormData();
    for (let i = 0; i < files.length; i++) {
      formData.append('arquivos', files[i]);
    }

    try {
      const response = await fetch('http://localhost:8000/processar-lote', {
        method: 'POST',
        body: formData
      });

      if (!response.ok) throw new Error(`Erro HTTP: ${response.status}`);

      const data = await response.json();
      setLaudos(data.laudos);
    } catch (error) {
      setErro(error instanceof Error ? error.message : 'Erro desconhecido');
    } finally {
      setLoading(false);
    }
  };

  const handleDrag = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === "dragenter" || e.type === "dragover") {
      setDragActive(true);
    } else if (e.type === "dragleave") {
      setDragActive(false);
    }
  }, []);

  const handleDrop = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);
    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      processarLaudos(e.dataTransfer.files);
    }
  }, []);

  const stats = {
    total: laudos.length,
    alta: laudos.filter(l => l.analise.prioridade === 'alta').length,
    media: laudos.filter(l => l.analise.prioridade === 'media').length,
    baixa: laudos.filter(l => l.analise.prioridade === 'baixa').length,
  };

  const getPrioridadeColor = (p: string) => ({
    'alta': 'border-red-500 bg-red-50',
    'media': 'border-yellow-500 bg-yellow-50',
    'baixa': 'border-green-500 bg-green-50'
  }[p] || 'border-gray-500 bg-gray-50');

  const getPrioridadeIcon = (p: string) => ({
    'alta': <AlertCircle className="w-6 h-6 text-red-500" />,
    'media': <Clock className="w-6 h-6 text-amber-500" />,
    'baixa': <CheckCircle className="w-6 h-6 text-emerald-500" />
  }[p]);

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 to-blue-100">
      <div className="bg-white shadow-sm border-b border-blue-200">
        <div className="max-w-7xl mx-auto px-4 py-4">
          <div className="flex items-center gap-4">
            <img 
              src="/logo.png" 
              alt="CardioScreen Logo" 
              className="h-14 w-auto"
            />
            <div>
              <p className="text-sm text-gray-600">Triagem Automatizada TAVI com IA</p>
            </div>
          </div>
        </div>
      </div>

      <div className="max-w-7xl mx-auto px-4 py-8">
        <div className="bg-white rounded-lg shadow-md p-8 mb-8">
          <h2 className="text-xl font-semibold mb-4">Upload de Laudos</h2>

          <div className="border-2 border-dashed border-gray-300 rounded-lg p-12 text-center hover:border-blue-500">
            <input
              type="file"
              multiple
              accept=".pdf"
              onChange={(e) => processarLaudos(e.target.files)}
              className="hidden"
              id="file-upload"
              disabled={loading}
            />
            <label htmlFor="file-upload" className="cursor-pointer flex flex-col items-center">
              <Upload className="w-16 h-16 text-blue-500 mb-4" />
              <span className="text-lg font-medium">Clique para selecionar PDFs</span>
            </label>
          </div>

          {loading && (
            <div className="mt-6 p-4 bg-blue-50 rounded-lg flex items-center gap-3">
              <div className="animate-spin rounded-full h-6 w-6 border-b-2 border-blue-600"></div>
              <span className="text-blue-700 font-medium">Processando com IA...</span>
            </div>
          )}

          {erro && (
            <div className="mt-6 p-4 bg-red-50 border border-red-200 rounded-lg flex items-center gap-2">
              <AlertCircle className="w-5 h-5 text-red-500" />
              <span className="text-red-700">Erro: {erro}</span>
            </div>
          )}
        </div>

        {laudos.length > 0 && (
          <div className="bg-white rounded-lg shadow-md p-8">
            <h2 className="text-2xl font-bold mb-6">
              Resultados ({laudos.length} {laudos.length === 1 ? 'laudo' : 'laudos'})
            </h2>

            <div className="space-y-4">
              {laudos.map((laudo, i) => (
                <div key={i} className={`border-l-4 rounded-lg p-6 ${getPrioridadeColor(laudo.analise.prioridade)}`}>
                  <div className="flex items-start justify-between mb-4">
                    <div className="flex items-center gap-3">
                      {getPrioridadeIcon(laudo.analise.prioridade)}
                      <div>
                        <h3 className="font-bold text-lg">{laudo.arquivo}</h3>
                        <p className="text-sm text-gray-600">
                          {new Date(laudo.timestamp).toLocaleString('pt-BR')}
                        </p>
                      </div>
                    </div>
                    <span className={`px-3 py-1 rounded-full text-sm font-semibold ${
                      laudo.analise.prioridade === 'alta' ? 'bg-red-600 text-white' :
                      laudo.analise.prioridade === 'media' ? 'bg-yellow-600 text-white' :
                      'bg-green-600 text-white'
                    }`}>
                      {laudo.analise.prioridade.toUpperCase()}
                    </span>
                  </div>

                  <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-4">
                    <div>
                      <p className="text-sm text-gray-600">Gravidade</p>
                      <p className="font-semibold capitalize">{laudo.analise.gravidade}</p>
                    </div>
                    <div>
                      <p className="text-sm text-gray-600">Área Valvar</p>
                      <p className="font-semibold">{laudo.analise.area_valvar || 'N/A'} cm²</p>
                    </div>
                    <div>
                      <p className="text-sm text-gray-600">Gradiente</p>
                      <p className="font-semibold">{laudo.analise.gradiente_medio || 'N/A'} mmHg</p>
                    </div>
                    <div>
                      <p className="text-sm text-gray-600">Velocidade</p>
                      <p className="font-semibold">{laudo.analise.velocidade_maxima || 'N/A'} m/s</p>
                    </div>
                  </div>

                  <div className="mb-4">
                    <p className="text-sm text-gray-600 mb-1">Análise</p>
                    <p className="text-gray-800">{laudo.analise.justificativa}</p>
                  </div>

                  <div className="flex items-center justify-between pt-4 border-t">
                    <div className="flex gap-4">
                      <span className={laudo.analise.indicacao_tavi ? 'text-red-600 font-medium' : 'text-gray-600'}>
                        {laudo.analise.indicacao_tavi ? '✓ Indicação TAVI' : '○ Sem indicação'}
                      </span>
                      <span className="text-gray-600">
                        Confiança: {(laudo.analise.confianca * 100).toFixed(0)}%
                      </span>
                    </div>
                    <button className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700">
                      Revisar
                    </button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>

      <div className="mt-12 pb-8 text-center text-gray-600 text-sm">
        <p>CardioScreen v1.0 - Powered by Claude Haiku</p>
      </div>
    </div>
  );
}

export default App;
